mapper.select:
select id
from house
where status = #{availableStatus}
  and latitude is not null
  and longitude is not null

      and id in

          #{candidateId}



      and rent_type = #{rentType}



          and total_cost <= #{maxComparableCostCent}


          and price <= #{maxComparableCostCent}


  and latitude between #{minLatitude} and #{maxLatitude}
  and longitude between #{minLongitude} and #{maxLongitude}
  and 6371.0 * 2 * asin(
        sqrt(
            power(sin(radians(latitude - #{targetLatitude}) / 2), 2)
            + cos(radians(#{targetLatitude}))
            * cos(radians(latitude))
            * power(sin(radians(longitude - #{targetLongitude}) / 2), 2)
        )
      ) <= #{radiusKm}



            order by total_cost asc, id desc


            order by price asc, id desc



limit #{limit}
